arguments.command:
cd /tmp/sv-0b31ea2a7445490db90dc1d0b46ea74c && \
# These addresses (0x2f4b20, 0x2f4c84) fall in .data.rel.ro, not .text
# Find nearest symbols in the symbol table
readelf -sW libmonosgen-2.0.so.dbg | awk '
$2 != "" && $4 != "FILE" {
  addr = strtonum("0x" $2)
  size = strtonum($3)
  if (addr > 0 && addr <= 0x2f4b20 && addr + size > 0x2f4b20) {
    printf "0x2f4b20 in: %s (0x%x size=%d type=%s)\n", $8, addr, size, $4
  }
  if (addr > 0 && addr <= 0x2f4c84 && addr + size > 0x2f4c84) {
    printf "0x2f4c84 in: %s (0x%x size=%d type=%s)\n", $8, addr, size, $4
  }
}' | sort -u

